module door_lock (
	input clk,
	input resetn,
	input key,
	output reg open);

	parameter LOCKED=0, UNLOCKED=1;
	reg unused_state, next_state;

	always @(posedge clk) begin
		if (~resetn) unused_state <= LOCKED;
		else unused_state <= next_state;
	end

	always_comb begin
		case (unused_state)
			LOCKED: next_state = key ? UNLOCKED : LOCKED;
			UNLOCKED: next_state = LOCKED;
			default: next_state = LOCKED;
		endcase
	end

	always @(unused_state) begin
		case (unused_state)
			UNLOCKED: open = 1;
			default: open = 0;
		endcase
	end
endmodule
